// macro code test starts here
enum custom_keycodes {
    SPL = SAFE_RANGE,
    PGUP_DBL, //2 page scroll up 
    PGDN_DBL, //2 page scroll down
    PAR, // ()
    CUR, // {}
    SQU, // []
    QUO, // ''
    DBLQUO, // ""
    CAPG // G
};

bool process_record_user(uint16_t keycode, keyrecord_t *record) {
  switch (keycode) {
    case SPL:
    	if (record->event.pressed) {
	      tap_code16(LCTL(KC_L));
    	  tap_code16(LSFT(KC_ENT));
	      tap_code(KC_PGDN);
	    }
     	return false;
	    break;
    case PGUP_DBL:
      if (record->event.pressed) {
        tap_code(KC_PGUP);
        tap_code(KC_PGUP);
        tap_code16(RGUI(KC_LEFT));
        tap_code(KC_PGUP);
        tap_code(KC_PGUP);
      }
      return false;
      break;
    case PGDN_DBL:
      if (record->event.pressed) {
        tap_code(KC_PGDN);
        tap_code(KC_PGDN);
        tap_code16(RGUI(KC_LEFT));
        tap_code(KC_PGDN);
        tap_code(KC_PGDN);
      }
      return false;
      break;
    //cancel rolled modifiers of same hand. Prevents modifiers accidental
    //press e.g. when press s and t key, stops ctrl + t behaviour.
    case LSFT_T(KC_T):
      if (record->event.pressed && record->tap.count > 0) {
        if (get_mods() & MOD_BIT(KC_LCTL)) {
          unregister_mods(MOD_BIT(KC_LCTL));
          tap_code(KC_S);
          tap_code(KC_T);
          add_mods(MOD_BIT(KC_LCTL));
          return false;
        }
      }
      return true;
     	break;
    case RSFT_T(KC_N):
      if (record->event.pressed && record->tap.count > 0) {
        if (get_mods() & MOD_BIT(KC_RCTL)) {
          unregister_mods(MOD_BIT(KC_RCTL));
          tap_code(KC_E);
          tap_code(KC_N);
          add_mods(MOD_BIT(KC_RCTL));
          return false;
        }
      }
      return true;
    	break;
    //enter goes back baselayer if layer set
    case KC_ENT:
      if (record->event.pressed) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2) 
          || IS_LAYER_ON(3)
          || IS_LAYER_ON(4)) {
          tap_code(KC_ENT);
          layer_clear();       
          return false;
        }
      }
      return true;
      break;
    //space key goes back to default layer from all layer
    case LT(3,KC_SPC):
      if (record->event.pressed) {
        if (IS_LAYER_ON(1) 
          || IS_LAYER_ON(2) 
          || IS_LAYER_ON(3)
          || IS_LAYER_ON(4)) {
          tap_code(KC_SPC);
          layer_clear();       
          return false;
        }
      }
      return true;
      break;
    //escape goes back baselayer if layer set
    case KC_ESC:
      if (record->event.pressed) {
        if (IS_LAYER_ON(1) || IS_LAYER_ON(2) || IS_LAYER_ON(4)) {
          layer_clear();       
          return false;
        }
      }
      return true;
      break;
    //macro for brackets
    case PAR: 
      if (record->event.pressed) {
	    //if shift pressed
        if(get_mods() & MOD_BIT(KC_LSFT)) {
          unregister_mods(MOD_BIT(KC_LSFT));	
	        SEND_STRING("()" SS_TAP(X_LEFT));
          add_mods(MOD_BIT(KC_LSFT));
          return false;
	    //if no shift pressed
        } else {
	        SEND_STRING("()"); 
        }
      } 
      return true;
      break;
    case CUR: 
      if(record->event.pressed) {
        if(get_mods() & MOD_BIT(KC_LSFT)) {
          unregister_mods(MOD_BIT(KC_LSFT));	
	        SEND_STRING("{}" SS_TAP(X_LEFT));
          add_mods(MOD_BIT(KC_LSFT));
          return false;
	    //if no shift pressed
        } else {
	        SEND_STRING("{}"); 
        }
      } 
      return true;
      break;
    case SQU: 
      if(record->event.pressed) {
	      if(get_mods() & MOD_BIT(KC_LSFT)) {
          unregister_mods(MOD_BIT(KC_LSFT));	
          SEND_STRING("[]" SS_TAP(X_LEFT));
          add_mods(MOD_BIT(KC_LSFT));
          return false;
	      //if no shift pressed
	      } else {
          SEND_STRING("[]"); 
	      }
      } 
      return true;
      break;
    //below needs to be added to combos to use right pinky keys
    case QUO: 
   	  if(record->event.pressed) {
  	    if(get_mods() & MOD_BIT(KC_LSFT)) {
  	     	unregister_mods(MOD_BIT(KC_LSFT));	
  	      SEND_STRING("''" SS_TAP(X_LEFT));
  		    add_mods(MOD_BIT(KC_LSFT));
  		    return false;
  	    //if no shift pressed
  	    } else {
  	      SEND_STRING("''"); 
  	    }
  	  } 
      return true;
	    break;
    case DBLQUO: 
   	  if(record->event.pressed) {
  	    if(get_mods() & MOD_BIT(KC_LSFT)) {
  	     	unregister_mods(MOD_BIT(KC_LSFT));	
  	      SEND_STRING("\"\"" SS_TAP(X_LEFT));
  		    add_mods(MOD_BIT(KC_LSFT));
  		    return false;
  	    //if no shift pressed
  	    } else {
  	      SEND_STRING("\"\""); 
  	    }
  	  } 
      return true;
	    break;
    case CAPG: 
   	  if(record->event.pressed) {
        register_mods(MOD_BIT(KC_RSFT));
        tap_code(KC_G);
        layer_clear();
        unregister_mods(MOD_BIT(KC_RSFT));
        return false;
  	  } 
      return true;
	    break;
  }
  return true;
};


